BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Hypertension, Hypotension, CO & SV' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Hypertension, Hypotension, CO & SV', 'Blood pressure physiology and management', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - HTN/Hypotension/CO/SV (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Hypertension Hypotension CO SV - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports BP formula in this hemodynamic scenario?', 'Which finding best supports BP formula in this hemodynamic scenario?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Blood pressure is determined by cardiac output multiplied by systemic vascular resistance (BP = CO × SVR)."}, {"id": "c", "text": "SVR has no influence on BP in this note."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["b"]'::jsonb, 'Correct because Blood pressure is determined by cardiac output multiplied by systemic vascular resistance (BP = CO × SVR). Interpret BP changes by evaluating both pump flow and vascular tone.', 'Hypertension Hypotension CO SV - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches CO formula?', 'The nurse interprets cardiovascular data. Which statement best matches CO formula?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "c", "text": "Heart rate does not affect CO in this note."}, {"id": "d", "text": "Assess tachy/bradycardia and stroke volume drivers when perfusion worsens."}]'::jsonb, '["d"]'::jsonb, 'Correct because Cardiac output equals stroke volume times heart rate (CO = SV × HR). Assess tachy/bradycardia and stroke volume drivers when perfusion worsens.', 'Hypertension Hypotension CO SV - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding MAP formula and normal?', 'Which clinical judgment is most accurate regarding MAP formula and normal?', '[{"id": "a", "text": "MAP is calculated as SBP + DBP divided by 2 in this note."}, {"id": "b", "text": "Normal MAP is listed as 30–50 in this note."}, {"id": "c", "text": "MAP is calculated as (2×DBP + SBP) ÷ 3 and normal range listed is 70–100 mmHg."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because MAP is calculated as (2×DBP + SBP) ÷ 3 and normal range listed is 70–100 mmHg. Use MAP for organ perfusion triage, not SBP alone.', 'Hypertension Hypotension CO SV - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Core definitions?', 'In urgent prioritization, which conclusion aligns with Core definitions?', '[{"id": "a", "text": "Distinguish preload/afterload effects when choosing interventions."}, {"id": "b", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "c", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "d", "text": "This pattern is more consistent with HTN risk factors."}]'::jsonb, '["a"]'::jsonb, 'Correct because BP is force against artery walls, CO is blood pumped per minute by LV, SV is blood per beat, SVR is resistance to LV ejection, preload is venous return stretch, afterload is resistance to ejection. Distinguish preload/afterload effects when choosing interventions.', 'Hypertension Hypotension CO SV - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects HTN staging normal/elevated?', 'Which option most appropriately reflects HTN staging normal/elevated?', '[{"id": "a", "text": "This pattern is more consistent with HTN complications."}, {"id": "b", "text": "Normal BP is <120/<80 and elevated is 120–129 systolic with diastolic <80."}, {"id": "c", "text": "Normal BP is listed as under 140/90 in this note."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["b"]'::jsonb, 'Correct because Normal BP is <120/<80 and elevated is 120–129 systolic with diastolic <80. Catch early elevation stage to prevent progression.', 'Hypertension Hypotension CO SV - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports HTN stages 1 and 2 in this hemodynamic scenario?', 'Which finding best supports HTN stages 1 and 2 in this hemodynamic scenario?', '[{"id": "a", "text": "Stage 2 requires SBP >200 in this note."}, {"id": "b", "text": "Stage classification guides urgency and treatment intensity."}, {"id": "c", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "d", "text": "Stage 1 starts at SBP 150 in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Stage 1 HTN is 130–139 or 80–89; stage 2 is ≥140 or ≥90. Stage classification guides urgency and treatment intensity.', 'Hypertension Hypotension CO SV - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches Hypertensive crisis threshold?', 'The nurse interprets cardiovascular data. Which statement best matches Hypertensive crisis threshold?', '[{"id": "a", "text": "Hypertensive crisis is listed as BP >180/>120."}, {"id": "b", "text": "Crisis starts at 150/90 in this note."}, {"id": "c", "text": "Crisis requires low BP in this note."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["a"]'::jsonb, 'Correct because Hypertensive crisis is listed as BP >180/>120. Escalate rapidly and assess for acute organ damage.', 'Hypertension Hypotension CO SV - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding HTN risk factors?', 'Which clinical judgment is most accurate regarding HTN risk factors?', '[{"id": "a", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "b", "text": "Age is modifiable in this note."}, {"id": "c", "text": "Target modifiable risks aggressively for BP control."}, {"id": "d", "text": "Stress has no relation to HTN in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Non-modifiable risks include age, family history, and race; modifiable include obesity, smoking, high sodium diet, sedentary lifestyle, alcohol, and stress. Target modifiable risks aggressively for BP control.', 'Hypertension Hypotension CO SV - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with HTN complications?', 'In urgent prioritization, which conclusion aligns with HTN complications?', '[{"id": "a", "text": "Only skin complications are listed in this note."}, {"id": "b", "text": "Complications listed are stroke, MI, heart failure, CKD, and retinal damage."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Complications listed are stroke, MI, heart failure, CKD, and retinal damage. Uncontrolled BP requires organ-protection strategy and close follow-up.', 'Hypertension Hypotension CO SV - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects Lifestyle HTN management?', 'Which option most appropriately reflects Lifestyle HTN management?', '[{"id": "a", "text": "Pair medication with sustained lifestyle adherence for long-term control."}, {"id": "b", "text": "Sedentary rest is first-line lifestyle in this note."}, {"id": "c", "text": "High-salt diet is recommended for HTN in this note."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["a"]'::jsonb, 'Correct because Lifestyle management includes DASH (lower sodium/higher potassium), exercise, weight loss, and smoking cessation. Pair medication with sustained lifestyle adherence for long-term control.', 'Hypertension Hypotension CO SV - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports ACE inhibitor specifics in this hemodynamic scenario?', 'Which finding best supports ACE inhibitor specifics in this hemodynamic scenario?', '[{"id": "a", "text": "ACE inhibitors are preferred during pregnancy in this note."}, {"id": "b", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "c", "text": "ACE inhibitors (e.g., lisinopril) can cause dry cough and are contraindicated in pregnancy."}, {"id": "d", "text": "This pattern is more consistent with MAP reduction limit."}]'::jsonb, '["c"]'::jsonb, 'Correct because ACE inhibitors (e.g., lisinopril) can cause dry cough and are contraindicated in pregnancy. Screen for pregnancy status and cough intolerance.', 'Hypertension Hypotension CO SV - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches ARB specifics?', 'The nurse interprets cardiovascular data. Which statement best matches ARB specifics?', '[{"id": "a", "text": "This pattern is more consistent with Hypotension definition."}, {"id": "b", "text": "ARBs worsen ACE cough in this note."}, {"id": "c", "text": "ARBs are only emergency IV drugs in this note."}, {"id": "d", "text": "Use ARB substitution when ACE cough limits adherence."}]'::jsonb, '["d"]'::jsonb, 'Correct because ARBs (e.g., losartan) are used if ACE inhibitors are not tolerated and do not cause cough per note. Use ARB substitution when ACE cough limits adherence.', 'Hypertension Hypotension CO SV - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Thiazide/CCB/beta-blocker roles?', 'Which clinical judgment is most accurate regarding Thiazide/CCB/beta-blocker roles?', '[{"id": "a", "text": "Thiazides are first-line for most patients, CCBs cause vasodilation, and beta-blockers reduce HR/contractility."}, {"id": "b", "text": "Beta-blockers increase contractility in this note."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "This pattern is more consistent with Hypotension types and causes."}]'::jsonb, '["a"]'::jsonb, 'Correct because Thiazides are first-line for most patients, CCBs cause vasodilation, and beta-blockers reduce HR/contractility. Match medication mechanism to hemodynamic target.', 'Hypertension Hypotension CO SV - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Hypertensive emergency treatment?', 'In urgent prioritization, which conclusion aligns with Hypertensive emergency treatment?', '[{"id": "a", "text": "No organ damage assessment is needed in this note."}, {"id": "b", "text": "This pattern is more consistent with Orthostatic criteria."}, {"id": "c", "text": "Treat with controlled IV reduction while monitoring perfusion."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Hypertensive emergency with organ damage requires IV antihypertensives such as nicardipine, labetalol, or nitroprusside. Treat with controlled IV reduction while monitoring perfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects MAP reduction limit?', 'Which option most appropriately reflects MAP reduction limit?', '[{"id": "a", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "b", "text": "In hypertensive emergency, MAP should not be reduced by more than 25% in the first hour."}, {"id": "c", "text": "Reduce MAP by 60% in first hour in this note."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because In hypertensive emergency, MAP should not be reduced by more than 25% in the first hour. Avoid overcorrection that can cause organ hypoperfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Hypotension definition in this hemodynamic scenario?', 'Which finding best supports Hypotension definition in this hemodynamic scenario?', '[{"id": "a", "text": "Treat symptomatic low BP rapidly to protect organ perfusion."}, {"id": "b", "text": "This pattern is more consistent with Hypotension symptoms."}, {"id": "c", "text": "Any low BP without symptoms is always shock in this note."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["a"]'::jsonb, 'Correct because Hypotension is systolic <90 or diastolic <60 and is significant when symptoms or hypoperfusion are present. Treat symptomatic low BP rapidly to protect organ perfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches Hypotension types and causes?', 'The nurse interprets cardiovascular data. Which statement best matches Hypotension types and causes?', '[{"id": "a", "text": "This pattern is more consistent with Hypotension treatment."}, {"id": "b", "text": "Only neurogenic hypotension exists in this note."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "Types listed are orthostatic, hypovolemic, neurogenic, and cardiogenic; causes include bleeding/dehydration, HF, sepsis, medications, and Addison disease."}]'::jsonb, '["d"]'::jsonb, 'Correct because Types listed are orthostatic, hypovolemic, neurogenic, and cardiogenic; causes include bleeding/dehydration, HF, sepsis, medications, and Addison disease. Identify subtype/cause to guide targeted therapy.', 'Hypertension Hypotension CO SV - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Orthostatic criteria?', 'Which clinical judgment is most accurate regarding Orthostatic criteria?', '[{"id": "a", "text": "Measure postural vitals correctly before labeling orthostasis."}, {"id": "b", "text": "This pattern is more consistent with CO factors: heart rate."}, {"id": "c", "text": "Orthostatic criteria require HR rise only in this note."}, {"id": "d", "text": "Drop must occur after 30 minutes in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Orthostatic hypotension is drop ≥20 systolic or ≥10 diastolic within 3 minutes of standing. Measure postural vitals correctly before labeling orthostasis.', 'Hypertension Hypotension CO SV - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Orthostatic management?', 'In urgent prioritization, which conclusion aligns with Orthostatic management?', '[{"id": "a", "text": "Hydration should be restricted in orthostasis in this note."}, {"id": "b", "text": "Nursing actions include dangling legs before standing, slow position changes, and adequate hydration."}, {"id": "c", "text": "This pattern is more consistent with CO factors: preload."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["b"]'::jsonb, 'Correct because Nursing actions include dangling legs before standing, slow position changes, and adequate hydration. Prevent falls and syncope with positional safety teaching.', 'Hypertension Hypotension CO SV - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects Hypotension symptoms?', 'Which option most appropriately reflects Hypotension symptoms?', '[{"id": "a", "text": "Warm flushed skin with high urine output is hallmark in this note."}, {"id": "b", "text": "Bradycardia is always present in this note."}, {"id": "c", "text": "Trend neuro, skin, pulse, and urine output for perfusion decline."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["c"]'::jsonb, 'Correct because Symptoms include dizziness, syncope, blurred vision, confusion, compensatory tachycardia, cool pale skin, and low urine output. Trend neuro, skin, pulse, and urine output for perfusion decline.', 'Hypertension Hypotension CO SV - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Hypotension treatment in this hemodynamic scenario?', 'Which finding best supports Hypotension treatment in this hemodynamic scenario?', '[{"id": "a", "text": "Diuresis is first-line for hypovolemic hypotension in this note."}, {"id": "b", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "c", "text": "Standing position is preferred in severe hypotension in this note."}, {"id": "d", "text": "Management includes treating cause, IV fluids or blood products for hypovolemia, vasopressors for severe cases, supine position with legs elevated, and slow postural changes."}]'::jsonb, '["d"]'::jsonb, 'Correct because Management includes treating cause, IV fluids or blood products for hypovolemia, vasopressors for severe cases, supine position with legs elevated, and slow postural changes. Restore circulating volume and perfusion while preventing recurrent drops.', 'Hypertension Hypotension CO SV - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches CO factors: heart rate?', 'The nurse interprets cardiovascular data. Which statement best matches CO factors: heart rate?', '[{"id": "a", "text": "This pattern is more consistent with BP formula."}, {"id": "b", "text": "Bradycardia always raises CO in this note."}, {"id": "c", "text": "Evaluate whether HR changes are compensatory or harmful to perfusion."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because CO can increase with tachycardia/epinephrine and decrease with bradycardia/beta-blockers per table. Evaluate whether HR changes are compensatory or harmful to perfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding CO factors: preload?', 'Which clinical judgment is most accurate regarding CO factors: preload?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Preload increase with fluid volume can raise CO; dehydration/hemorrhage lower preload and CO."}, {"id": "c", "text": "Hemorrhage raises preload in this note."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["b"]'::jsonb, 'Correct because Preload increase with fluid volume can raise CO; dehydration/hemorrhage lower preload and CO. Volume assessment is central in hypotension and shock states.', 'Hypertension Hypotension CO SV - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with CO factors: afterload/contractility?', 'In urgent prioritization, which conclusion aligns with CO factors: afterload/contractility?', '[{"id": "a", "text": "Vasoconstriction always increases CO in this note."}, {"id": "b", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "c", "text": "Balance vascular tone and contractility when optimizing output."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["c"]'::jsonb, 'Correct because Vasodilation (lower SVR) can improve CO while vasoconstriction (higher SVR) can reduce CO; contractility rises with digoxin/epinephrine and falls with HF/MI. Balance vascular tone and contractility when optimizing output.', 'Hypertension Hypotension CO SV - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects NCLEX MAP warning?', 'Which option most appropriately reflects NCLEX MAP warning?', '[{"id": "a", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "b", "text": "No action needed unless MAP <20 in this note."}, {"id": "c", "text": "MAP below 60 mmHg means organs are at risk of ischemia and immediate BP/oxygenation support is priority."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because MAP below 60 mmHg means organs are at risk of ischemia and immediate BP/oxygenation support is priority. Treat MAP <60 as urgent perfusion threat.', 'Hypertension Hypotension CO SV - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports BP formula in this hemodynamic scenario?', 'Which finding best supports BP formula in this hemodynamic scenario?', '[{"id": "a", "text": "SVR has no influence on BP in this note."}, {"id": "b", "text": "Interpret BP changes by evaluating both pump flow and vascular tone."}, {"id": "c", "text": "BP equals HR minus SV in this note."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Blood pressure is determined by cardiac output multiplied by systemic vascular resistance (BP = CO × SVR). Interpret BP changes by evaluating both pump flow and vascular tone.', 'Hypertension Hypotension CO SV - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches CO formula?', 'The nurse interprets cardiovascular data. Which statement best matches CO formula?', '[{"id": "a", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "b", "text": "This pattern is more consistent with HTN stages 1 and 2."}, {"id": "c", "text": "Cardiac output equals stroke volume times heart rate (CO = SV × HR)."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Cardiac output equals stroke volume times heart rate (CO = SV × HR). Assess tachy/bradycardia and stroke volume drivers when perfusion worsens.', 'Hypertension Hypotension CO SV - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding MAP formula and normal?', 'Which clinical judgment is most accurate regarding MAP formula and normal?', '[{"id": "a", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "b", "text": "Use MAP for organ perfusion triage, not SBP alone."}, {"id": "c", "text": "MAP is calculated as SBP + DBP divided by 2 in this note."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because MAP is calculated as (2×DBP + SBP) ÷ 3 and normal range listed is 70–100 mmHg. Use MAP for organ perfusion triage, not SBP alone.', 'Hypertension Hypotension CO SV - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Core definitions?', 'In urgent prioritization, which conclusion aligns with Core definitions?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "BP is force against artery walls, CO is blood pumped per minute by LV, SV is blood per beat, SVR is resistance to LV ejection, preload is venous return stretch, afterload is resistance to ejection."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "SVR is defined as oxygen saturation in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because BP is force against artery walls, CO is blood pumped per minute by LV, SV is blood per beat, SVR is resistance to LV ejection, preload is venous return stretch, afterload is resistance to ejection. Distinguish preload/afterload effects when choosing interventions.', 'Hypertension Hypotension CO SV - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects HTN staging normal/elevated?', 'Which option most appropriately reflects HTN staging normal/elevated?', '[{"id": "a", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "b", "text": "Normal BP is listed as under 140/90 in this note."}, {"id": "c", "text": "Catch early elevation stage to prevent progression."}, {"id": "d", "text": "This pattern is more consistent with HTN complications."}]'::jsonb, '["c"]'::jsonb, 'Correct because Normal BP is <120/<80 and elevated is 120–129 systolic with diastolic <80. Catch early elevation stage to prevent progression.', 'Hypertension Hypotension CO SV - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports HTN stages 1 and 2 in this hemodynamic scenario?', 'Which finding best supports HTN stages 1 and 2 in this hemodynamic scenario?', '[{"id": "a", "text": "Stage 2 requires SBP >200 in this note."}, {"id": "b", "text": "Stage 1 HTN is 130–139 or 80–89; stage 2 is ≥140 or ≥90."}, {"id": "c", "text": "This pattern is more consistent with Lifestyle HTN management."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Stage 1 HTN is 130–139 or 80–89; stage 2 is ≥140 or ≥90. Stage classification guides urgency and treatment intensity.', 'Hypertension Hypotension CO SV - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches Hypertensive crisis threshold?', 'The nurse interprets cardiovascular data. Which statement best matches Hypertensive crisis threshold?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Crisis starts at 150/90 in this note."}, {"id": "c", "text": "Escalate rapidly and assess for acute organ damage."}, {"id": "d", "text": "This pattern is more consistent with ACE inhibitor specifics."}]'::jsonb, '["c"]'::jsonb, 'Correct because Hypertensive crisis is listed as BP >180/>120. Escalate rapidly and assess for acute organ damage.', 'Hypertension Hypotension CO SV - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding HTN risk factors?', 'Which clinical judgment is most accurate regarding HTN risk factors?', '[{"id": "a", "text": "Non-modifiable risks include age, family history, and race; modifiable include obesity, smoking, high sodium diet, sedentary lifestyle, alcohol, and stress."}, {"id": "b", "text": "Age is modifiable in this note."}, {"id": "c", "text": "Stress has no relation to HTN in this note."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["a"]'::jsonb, 'Correct because Non-modifiable risks include age, family history, and race; modifiable include obesity, smoking, high sodium diet, sedentary lifestyle, alcohol, and stress. Target modifiable risks aggressively for BP control.', 'Hypertension Hypotension CO SV - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with HTN complications?', 'In urgent prioritization, which conclusion aligns with HTN complications?', '[{"id": "a", "text": "Only skin complications are listed in this note."}, {"id": "b", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "Uncontrolled BP requires organ-protection strategy and close follow-up."}]'::jsonb, '["d"]'::jsonb, 'Correct because Complications listed are stroke, MI, heart failure, CKD, and retinal damage. Uncontrolled BP requires organ-protection strategy and close follow-up.', 'Hypertension Hypotension CO SV - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects Lifestyle HTN management?', 'Which option most appropriately reflects Lifestyle HTN management?', '[{"id": "a", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "b", "text": "Lifestyle management includes DASH (lower sodium/higher potassium), exercise, weight loss, and smoking cessation."}, {"id": "c", "text": "High-salt diet is recommended for HTN in this note."}, {"id": "d", "text": "Sedentary rest is first-line lifestyle in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Lifestyle management includes DASH (lower sodium/higher potassium), exercise, weight loss, and smoking cessation. Pair medication with sustained lifestyle adherence for long-term control.', 'Hypertension Hypotension CO SV - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports ACE inhibitor specifics in this hemodynamic scenario?', 'Which finding best supports ACE inhibitor specifics in this hemodynamic scenario?', '[{"id": "a", "text": "This pattern is more consistent with MAP reduction limit."}, {"id": "b", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "c", "text": "ACE inhibitors are preferred during pregnancy in this note."}, {"id": "d", "text": "Screen for pregnancy status and cough intolerance."}]'::jsonb, '["d"]'::jsonb, 'Correct because ACE inhibitors (e.g., lisinopril) can cause dry cough and are contraindicated in pregnancy. Screen for pregnancy status and cough intolerance.', 'Hypertension Hypotension CO SV - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches ARB specifics?', 'The nurse interprets cardiovascular data. Which statement best matches ARB specifics?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "This pattern is more consistent with Hypotension definition."}, {"id": "c", "text": "ARBs (e.g., losartan) are used if ACE inhibitors are not tolerated and do not cause cough per note."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["c"]'::jsonb, 'Correct because ARBs (e.g., losartan) are used if ACE inhibitors are not tolerated and do not cause cough per note. Use ARB substitution when ACE cough limits adherence.', 'Hypertension Hypotension CO SV - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Thiazide/CCB/beta-blocker roles?', 'Which clinical judgment is most accurate regarding Thiazide/CCB/beta-blocker roles?', '[{"id": "a", "text": "CCBs are listed as preload boosters in this note."}, {"id": "b", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "Match medication mechanism to hemodynamic target."}]'::jsonb, '["d"]'::jsonb, 'Correct because Thiazides are first-line for most patients, CCBs cause vasodilation, and beta-blockers reduce HR/contractility. Match medication mechanism to hemodynamic target.', 'Hypertension Hypotension CO SV - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Hypertensive emergency treatment?', 'In urgent prioritization, which conclusion aligns with Hypertensive emergency treatment?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "c", "text": "Oral-only delayed treatment is recommended in this note."}, {"id": "d", "text": "Hypertensive emergency with organ damage requires IV antihypertensives such as nicardipine, labetalol, or nitroprusside."}]'::jsonb, '["d"]'::jsonb, 'Correct because Hypertensive emergency with organ damage requires IV antihypertensives such as nicardipine, labetalol, or nitroprusside. Treat with controlled IV reduction while monitoring perfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects MAP reduction limit?', 'Which option most appropriately reflects MAP reduction limit?', '[{"id": "a", "text": "MAP has no role in emergency treatment in this note."}, {"id": "b", "text": "Avoid overcorrection that can cause organ hypoperfusion."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "Reduce MAP by 60% in first hour in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because In hypertensive emergency, MAP should not be reduced by more than 25% in the first hour. Avoid overcorrection that can cause organ hypoperfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Hypotension definition in this hemodynamic scenario?', 'Which finding best supports Hypotension definition in this hemodynamic scenario?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Hypotension is systolic <90 or diastolic <60 and is significant when symptoms or hypoperfusion are present."}, {"id": "c", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "d", "text": "Hypotension is defined as SBP under 130 in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Hypotension is systolic <90 or diastolic <60 and is significant when symptoms or hypoperfusion are present. Treat symptomatic low BP rapidly to protect organ perfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches Hypotension types and causes?', 'The nurse interprets cardiovascular data. Which statement best matches Hypotension types and causes?', '[{"id": "a", "text": "This pattern is more consistent with Hypotension treatment."}, {"id": "b", "text": "Sepsis cannot cause hypotension in this note."}, {"id": "c", "text": "Identify subtype/cause to guide targeted therapy."}, {"id": "d", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Types listed are orthostatic, hypovolemic, neurogenic, and cardiogenic; causes include bleeding/dehydration, HF, sepsis, medications, and Addison disease. Identify subtype/cause to guide targeted therapy.', 'Hypertension Hypotension CO SV - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Orthostatic criteria?', 'Which clinical judgment is most accurate regarding Orthostatic criteria?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Drop must occur after 30 minutes in this note."}, {"id": "c", "text": "Orthostatic hypotension is drop ≥20 systolic or ≥10 diastolic within 3 minutes of standing."}, {"id": "d", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}]'::jsonb, '["c"]'::jsonb, 'Correct because Orthostatic hypotension is drop ≥20 systolic or ≥10 diastolic within 3 minutes of standing. Measure postural vitals correctly before labeling orthostasis.', 'Hypertension Hypotension CO SV - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Orthostatic management?', 'In urgent prioritization, which conclusion aligns with Orthostatic management?', '[{"id": "a", "text": "This pattern is more consistent with CO factors: preload."}, {"id": "b", "text": "Prevent falls and syncope with positional safety teaching."}, {"id": "c", "text": "Hydration should be restricted in orthostasis in this note."}, {"id": "d", "text": "Rapid standing is preferred in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Nursing actions include dangling legs before standing, slow position changes, and adequate hydration. Prevent falls and syncope with positional safety teaching.', 'Hypertension Hypotension CO SV - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects Hypotension symptoms?', 'Which option most appropriately reflects Hypotension symptoms?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Warm flushed skin with high urine output is hallmark in this note."}, {"id": "c", "text": "Symptoms include dizziness, syncope, blurred vision, confusion, compensatory tachycardia, cool pale skin, and low urine output."}, {"id": "d", "text": "This pattern is more consistent with CO factors: afterload/contractility."}]'::jsonb, '["c"]'::jsonb, 'Correct because Symptoms include dizziness, syncope, blurred vision, confusion, compensatory tachycardia, cool pale skin, and low urine output. Trend neuro, skin, pulse, and urine output for perfusion decline.', 'Hypertension Hypotension CO SV - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Hypotension treatment in this hemodynamic scenario?', 'Which finding best supports Hypotension treatment in this hemodynamic scenario?', '[{"id": "a", "text": "This pattern is more consistent with NCLEX MAP warning."}, {"id": "b", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "c", "text": "Restore circulating volume and perfusion while preventing recurrent drops."}, {"id": "d", "text": "Standing position is preferred in severe hypotension in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Management includes treating cause, IV fluids or blood products for hypovolemia, vasopressors for severe cases, supine position with legs elevated, and slow postural changes. Restore circulating volume and perfusion while preventing recurrent drops.', 'Hypertension Hypotension CO SV - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse interprets cardiovascular data. Which statement best matches CO factors: heart rate?', 'The nurse interprets cardiovascular data. Which statement best matches CO factors: heart rate?', '[{"id": "a", "text": "CO can increase with tachycardia/epinephrine and decrease with bradycardia/beta-blockers per table."}, {"id": "b", "text": "This pattern is more consistent with BP formula."}, {"id": "c", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "d", "text": "HR has no relation to CO in this table."}]'::jsonb, '["a"]'::jsonb, 'Correct because CO can increase with tachycardia/epinephrine and decrease with bradycardia/beta-blockers per table. Evaluate whether HR changes are compensatory or harmful to perfusion.', 'Hypertension Hypotension CO SV - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding CO factors: preload?', 'Which clinical judgment is most accurate regarding CO factors: preload?', '[{"id": "a", "text": "Because perfusion appears stable, immediate reassessment is unnecessary."}, {"id": "b", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "c", "text": "Volume assessment is central in hypotension and shock states."}, {"id": "d", "text": "Preload is unaffected by fluid status in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Preload increase with fluid volume can raise CO; dehydration/hemorrhage lower preload and CO. Volume assessment is central in hypotension and shock states.', 'Hypertension Hypotension CO SV - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with CO factors: afterload/contractility?', 'In urgent prioritization, which conclusion aligns with CO factors: afterload/contractility?', '[{"id": "a", "text": "Vasodilation (lower SVR) can improve CO while vasoconstriction (higher SVR) can reduce CO; contractility rises with digoxin/epinephrine and falls with HF/MI."}, {"id": "b", "text": "HF improves contractility in this note."}, {"id": "c", "text": "Vasoconstriction always increases CO in this note."}, {"id": "d", "text": "This pattern is more consistent with MAP formula and normal."}]'::jsonb, '["a"]'::jsonb, 'Correct because Vasodilation (lower SVR) can improve CO while vasoconstriction (higher SVR) can reduce CO; contractility rises with digoxin/epinephrine and falls with HF/MI. Balance vascular tone and contractility when optimizing output.', 'Hypertension Hypotension CO SV - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which option most appropriately reflects NCLEX MAP warning?', 'Which option most appropriately reflects NCLEX MAP warning?', '[{"id": "a", "text": "Treat MAP <60 as urgent perfusion threat."}, {"id": "b", "text": "Aggressive BP shifts are always preferred regardless of organ perfusion."}, {"id": "c", "text": "This pattern is more consistent with Core definitions."}, {"id": "d", "text": "No action needed unless MAP <20 in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because MAP below 60 mmHg means organs are at risk of ischemia and immediate BP/oxygenation support is priority. Treat MAP <60 as urgent perfusion threat.', 'Hypertension Hypotension CO SV - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for BP formula. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for BP formula. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "BP depends on both CO and SVR."}, {"id": "b", "text": "Rising SVR can increase BP when CO constant."}, {"id": "c", "text": "SVR has no influence on BP in this note."}, {"id": "d", "text": "BP equals HR minus SV in this note."}, {"id": "e", "text": "Falling CO can lower BP if SVR unchanged."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Blood pressure is determined by cardiac output multiplied by systemic vascular resistance (BP = CO × SVR).', 'Hypertension Hypotension CO SV - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and CO formula, which statements are correct? (Select all that apply)', 'For blood pressure management and CO formula, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "CO combines HR and SV."}, {"id": "b", "text": "Changes in either HR or SV change CO."}, {"id": "c", "text": "Heart rate does not affect CO in this note."}, {"id": "d", "text": "Formula is explicitly provided in note."}, {"id": "e", "text": "CO equals MAP divided by pulse pressure in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Cardiac output equals stroke volume times heart rate (CO = SV × HR).', 'Hypertension Hypotension CO SV - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around MAP formula and normal. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around MAP formula and normal. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Normal MAP is listed as 30–50 in this note."}, {"id": "b", "text": "MAP interpretation is key for perfusion."}, {"id": "c", "text": "Normal MAP range listed is 70–100."}, {"id": "d", "text": "MAP formula weights diastolic pressure twice."}, {"id": "e", "text": "MAP is calculated as SBP + DBP divided by 2 in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: MAP is calculated as (2×DBP + SBP) ÷ 3 and normal range listed is 70–100 mmHg.', 'Hypertension Hypotension CO SV - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Core definitions? (Select all that apply)', 'During reassessment, which observations support Core definitions? (Select all that apply)', '[{"id": "a", "text": "SVR is defined as oxygen saturation in this note."}, {"id": "b", "text": "Afterload means venous return volume in this note."}, {"id": "c", "text": "SV is blood volume pumped per beat in this note."}, {"id": "d", "text": "Afterload is resistance to ejection in this note."}, {"id": "e", "text": "Preload is venous return/stretch in this note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: BP is force against artery walls, CO is blood pumped per minute by LV, SV is blood per beat, SVR is resistance to LV ejection, preload is venous return stretch, afterload is resistance to ejection.', 'Hypertension Hypotension CO SV - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with HTN staging normal/elevated from this note? (Select all that apply)', 'Which clues are consistent with HTN staging normal/elevated from this note? (Select all that apply)', '[{"id": "a", "text": "Elevated is not yet stage 1 in this note."}, {"id": "b", "text": "Normal is below 120/80 in this note."}, {"id": "c", "text": "Elevated has SBP 120–129 with DBP <80."}, {"id": "d", "text": "Elevated BP requires DBP over 90 in this note."}, {"id": "e", "text": "Normal BP is listed as under 140/90 in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Normal BP is <120/<80 and elevated is 120–129 systolic with diastolic <80.', 'Hypertension Hypotension CO SV - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for HTN stages 1 and 2. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for HTN stages 1 and 2. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Diastolic thresholds are 80–89 for stage 1 and ≥90 for stage 2."}, {"id": "b", "text": "Stage 1 includes 130–139 systolic."}, {"id": "c", "text": "Stage 2 begins at 140 systolic."}, {"id": "d", "text": "Stage 1 starts at SBP 150 in this note."}, {"id": "e", "text": "Stage 2 requires SBP >200 in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Stage 1 HTN is 130–139 or 80–89; stage 2 is ≥140 or ≥90.', 'Hypertension Hypotension CO SV - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and Hypertensive crisis threshold, which statements are correct? (Select all that apply)', 'For blood pressure management and Hypertensive crisis threshold, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Crisis threshold includes systolic above 180."}, {"id": "b", "text": "Crisis requires low BP in this note."}, {"id": "c", "text": "Crisis starts at 150/90 in this note."}, {"id": "d", "text": "Crisis threshold includes diastolic above 120."}, {"id": "e", "text": "Crisis is higher risk than stage 2 in this note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypertensive crisis is listed as BP >180/>120.', 'Hypertension Hypotension CO SV - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around HTN risk factors. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around HTN risk factors. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Stress has no relation to HTN in this note."}, {"id": "b", "text": "Smoking and obesity are modifiable risks."}, {"id": "c", "text": "High sodium intake is listed modifiable risk."}, {"id": "d", "text": "Age is modifiable in this note."}, {"id": "e", "text": "Family history is listed non-modifiable risk."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Non-modifiable risks include age, family history, and race; modifiable include obesity, smoking, high sodium diet, sedentary lifestyle, alcohol, and stress.', 'Hypertension Hypotension CO SV - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support HTN complications? (Select all that apply)', 'During reassessment, which observations support HTN complications? (Select all that apply)', '[{"id": "a", "text": "Stroke and MI are listed complications."}, {"id": "b", "text": "Only skin complications are listed in this note."}, {"id": "c", "text": "CKD is listed complication."}, {"id": "d", "text": "HTN has no end-organ complications in this note."}, {"id": "e", "text": "Retinal damage is listed complication."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Complications listed are stroke, MI, heart failure, CKD, and retinal damage.', 'Hypertension Hypotension CO SV - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Lifestyle HTN management from this note? (Select all that apply)', 'Which clues are consistent with Lifestyle HTN management from this note? (Select all that apply)', '[{"id": "a", "text": "Sedentary rest is first-line lifestyle in this note."}, {"id": "b", "text": "Exercise and weight loss are recommended."}, {"id": "c", "text": "DASH diet is recommended."}, {"id": "d", "text": "High-salt diet is recommended for HTN in this note."}, {"id": "e", "text": "Smoking cessation is part of plan."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Lifestyle management includes DASH (lower sodium/higher potassium), exercise, weight loss, and smoking cessation.', 'Hypertension Hypotension CO SV - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for ACE inhibitor specifics. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for ACE inhibitor specifics. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "ACE inhibitors are contraindicated in pregnancy."}, {"id": "b", "text": "ACE inhibitors have no cough risk in this note."}, {"id": "c", "text": "Lisinopril is listed ACE example."}, {"id": "d", "text": "ACE inhibitors are preferred during pregnancy in this note."}, {"id": "e", "text": "Dry cough is a listed ACE inhibitor side effect."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: ACE inhibitors (e.g., lisinopril) can cause dry cough and are contraindicated in pregnancy.', 'Hypertension Hypotension CO SV - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and ARB specifics, which statements are correct? (Select all that apply)', 'For blood pressure management and ARB specifics, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Losartan is listed ARB example."}, {"id": "b", "text": "ARBs are only emergency IV drugs in this note."}, {"id": "c", "text": "ARBs are used when ACE not tolerated."}, {"id": "d", "text": "No-cough advantage is highlighted."}, {"id": "e", "text": "ARBs worsen ACE cough in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: ARBs (e.g., losartan) are used if ACE inhibitors are not tolerated and do not cause cough per note.', 'Hypertension Hypotension CO SV - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Thiazide/CCB/beta-blocker roles. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around Thiazide/CCB/beta-blocker roles. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "CCBs are listed as preload boosters in this note."}, {"id": "b", "text": "Beta-blockers increase contractility in this note."}, {"id": "c", "text": "HCTZ is listed first-line for many patients."}, {"id": "d", "text": "Metoprolol lowers HR and contractility."}, {"id": "e", "text": "Amlodipine is listed for vasodilation."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Thiazides are first-line for most patients, CCBs cause vasodilation, and beta-blockers reduce HR/contractility.', 'Hypertension Hypotension CO SV - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Hypertensive emergency treatment? (Select all that apply)', 'During reassessment, which observations support Hypertensive emergency treatment? (Select all that apply)', '[{"id": "a", "text": "IV nicardipine/labetalol/nitroprusside are listed."}, {"id": "b", "text": "Oral-only delayed treatment is recommended in this note."}, {"id": "c", "text": "Emergency is distinct from asymptomatic severe HTN."}, {"id": "d", "text": "No organ damage assessment is needed in this note."}, {"id": "e", "text": "Organ damage presence defines emergency context."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypertensive emergency with organ damage requires IV antihypertensives such as nicardipine, labetalol, or nitroprusside.', 'Hypertension Hypotension CO SV - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with MAP reduction limit from this note? (Select all that apply)', 'Which clues are consistent with MAP reduction limit from this note? (Select all that apply)', '[{"id": "a", "text": "First-hour MAP reduction cap is 25%."}, {"id": "b", "text": "MAP has no role in emergency treatment in this note."}, {"id": "c", "text": "Rapid excessive reduction is unsafe."}, {"id": "d", "text": "Reduce MAP by 60% in first hour in this note."}, {"id": "e", "text": "MAP-guided titration is emphasized."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: In hypertensive emergency, MAP should not be reduced by more than 25% in the first hour.', 'Hypertension Hypotension CO SV - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Hypotension definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Hypotension definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Any low BP without symptoms is always shock in this note."}, {"id": "b", "text": "DBP under 60 is hypotension in this note."}, {"id": "c", "text": "Hypotension is defined as SBP under 130 in this note."}, {"id": "d", "text": "Clinical significance depends on perfusion impact."}, {"id": "e", "text": "SBP under 90 is hypotension in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypotension is systolic <90 or diastolic <60 and is significant when symptoms or hypoperfusion are present.', 'Hypertension Hypotension CO SV - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and Hypotension types and causes, which statements are correct? (Select all that apply)', 'For blood pressure management and Hypotension types and causes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Meds and Addison disease are listed causes."}, {"id": "b", "text": "Orthostatic and hypovolemic are listed types."}, {"id": "c", "text": "Only neurogenic hypotension exists in this note."}, {"id": "d", "text": "Sepsis and HF are listed causes."}, {"id": "e", "text": "Sepsis cannot cause hypotension in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Types listed are orthostatic, hypovolemic, neurogenic, and cardiogenic; causes include bleeding/dehydration, HF, sepsis, medications, and Addison disease.', 'Hypertension Hypotension CO SV - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Orthostatic criteria. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around Orthostatic criteria. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Diastolic drop threshold is 10 mmHg."}, {"id": "b", "text": "Orthostatic criteria require HR rise only in this note."}, {"id": "c", "text": "Systolic drop threshold is 20 mmHg."}, {"id": "d", "text": "Timing window is within 3 minutes of standing."}, {"id": "e", "text": "Drop must occur after 30 minutes in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Orthostatic hypotension is drop ≥20 systolic or ≥10 diastolic within 3 minutes of standing.', 'Hypertension Hypotension CO SV - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Orthostatic management? (Select all that apply)', 'During reassessment, which observations support Orthostatic management? (Select all that apply)', '[{"id": "a", "text": "Dangle legs before standing is listed."}, {"id": "b", "text": "Rapid standing is preferred in this note."}, {"id": "c", "text": "Hydration should be restricted in orthostasis in this note."}, {"id": "d", "text": "Hydration support is recommended."}, {"id": "e", "text": "Slow position changes are recommended."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Nursing actions include dangling legs before standing, slow position changes, and adequate hydration.', 'Hypertension Hypotension CO SV - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Hypotension symptoms from this note? (Select all that apply)', 'Which clues are consistent with Hypotension symptoms from this note? (Select all that apply)', '[{"id": "a", "text": "Syncope/dizziness are listed symptoms."}, {"id": "b", "text": "Low urine output is listed symptom."}, {"id": "c", "text": "Bradycardia is always present in this note."}, {"id": "d", "text": "Warm flushed skin with high urine output is hallmark in this note."}, {"id": "e", "text": "Cool pale skin and tachycardia are listed."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Symptoms include dizziness, syncope, blurred vision, confusion, compensatory tachycardia, cool pale skin, and low urine output.', 'Hypertension Hypotension CO SV - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Hypotension treatment. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Hypotension treatment. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Supine with legs elevated is listed positioning."}, {"id": "b", "text": "IV fluids/blood products used if hypovolemic."}, {"id": "c", "text": "Standing position is preferred in severe hypotension in this note."}, {"id": "d", "text": "Diuresis is first-line for hypovolemic hypotension in this note."}, {"id": "e", "text": "Norepinephrine/dopamine listed for severe hypotension."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Management includes treating cause, IV fluids or blood products for hypovolemia, vasopressors for severe cases, supine position with legs elevated, and slow postural changes.', 'Hypertension Hypotension CO SV - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and CO factors: heart rate, which statements are correct? (Select all that apply)', 'For blood pressure management and CO factors: heart rate, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Bradycardia can lower CO in table."}, {"id": "b", "text": "Bradycardia always raises CO in this note."}, {"id": "c", "text": "HR has no relation to CO in this table."}, {"id": "d", "text": "Beta-blockers can lower CO via HR effects in table."}, {"id": "e", "text": "Tachycardia and epinephrine can raise CO in table."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: CO can increase with tachycardia/epinephrine and decrease with bradycardia/beta-blockers per table.', 'Hypertension Hypotension CO SV - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around CO factors: preload. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around CO factors: preload. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Hemorrhage raises preload in this note."}, {"id": "b", "text": "Hemorrhage lowers preload in table."}, {"id": "c", "text": "Preload is unaffected by fluid status in this note."}, {"id": "d", "text": "Higher fluid volume can increase preload/CO."}, {"id": "e", "text": "Dehydration lowers preload in table."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Preload increase with fluid volume can raise CO; dehydration/hemorrhage lower preload and CO.', 'Hypertension Hypotension CO SV - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support CO factors: afterload/contractility? (Select all that apply)', 'During reassessment, which observations support CO factors: afterload/contractility? (Select all that apply)', '[{"id": "a", "text": "HF improves contractility in this note."}, {"id": "b", "text": "HF/MI decrease contractility in table."}, {"id": "c", "text": "Digoxin/epinephrine increase contractility in table."}, {"id": "d", "text": "Higher SVR can reduce CO in the table context."}, {"id": "e", "text": "Vasoconstriction always increases CO in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Vasodilation (lower SVR) can improve CO while vasoconstriction (higher SVR) can reduce CO; contractility rises with digoxin/epinephrine and falls with HF/MI.', 'Hypertension Hypotension CO SV - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with NCLEX MAP warning from this note? (Select all that apply)', 'Which clues are consistent with NCLEX MAP warning from this note? (Select all that apply)', '[{"id": "a", "text": "No action needed unless MAP <20 in this note."}, {"id": "b", "text": "Oxygenation support is also prioritized."}, {"id": "c", "text": "Immediate BP support is prioritized."}, {"id": "d", "text": "MAP <60 is ischemia risk in note tip."}, {"id": "e", "text": "MAP 55 is acceptable organ perfusion in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: MAP below 60 mmHg means organs are at risk of ischemia and immediate BP/oxygenation support is priority.', 'Hypertension Hypotension CO SV - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for BP formula. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for BP formula. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Falling CO can lower BP if SVR unchanged."}, {"id": "b", "text": "Rising SVR can increase BP when CO constant."}, {"id": "c", "text": "BP depends on both CO and SVR."}, {"id": "d", "text": "BP equals HR minus SV in this note."}, {"id": "e", "text": "SVR has no influence on BP in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Blood pressure is determined by cardiac output multiplied by systemic vascular resistance (BP = CO × SVR).', 'Hypertension Hypotension CO SV - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and CO formula, which statements are correct? (Select all that apply)', 'For blood pressure management and CO formula, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "CO equals MAP divided by pulse pressure in this note."}, {"id": "b", "text": "Formula is explicitly provided in note."}, {"id": "c", "text": "Heart rate does not affect CO in this note."}, {"id": "d", "text": "Changes in either HR or SV change CO."}, {"id": "e", "text": "CO combines HR and SV."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiac output equals stroke volume times heart rate (CO = SV × HR).', 'Hypertension Hypotension CO SV - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around MAP formula and normal. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around MAP formula and normal. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "MAP formula weights diastolic pressure twice."}, {"id": "b", "text": "MAP is calculated as SBP + DBP divided by 2 in this note."}, {"id": "c", "text": "Normal MAP range listed is 70–100."}, {"id": "d", "text": "Normal MAP is listed as 30–50 in this note."}, {"id": "e", "text": "MAP interpretation is key for perfusion."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: MAP is calculated as (2×DBP + SBP) ÷ 3 and normal range listed is 70–100 mmHg.', 'Hypertension Hypotension CO SV - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Core definitions? (Select all that apply)', 'During reassessment, which observations support Core definitions? (Select all that apply)', '[{"id": "a", "text": "Afterload is resistance to ejection in this note."}, {"id": "b", "text": "Afterload means venous return volume in this note."}, {"id": "c", "text": "SV is blood volume pumped per beat in this note."}, {"id": "d", "text": "SVR is defined as oxygen saturation in this note."}, {"id": "e", "text": "Preload is venous return/stretch in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: BP is force against artery walls, CO is blood pumped per minute by LV, SV is blood per beat, SVR is resistance to LV ejection, preload is venous return stretch, afterload is resistance to ejection.', 'Hypertension Hypotension CO SV - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with HTN staging normal/elevated from this note? (Select all that apply)', 'Which clues are consistent with HTN staging normal/elevated from this note? (Select all that apply)', '[{"id": "a", "text": "Elevated has SBP 120–129 with DBP <80."}, {"id": "b", "text": "Elevated is not yet stage 1 in this note."}, {"id": "c", "text": "Normal BP is listed as under 140/90 in this note."}, {"id": "d", "text": "Elevated BP requires DBP over 90 in this note."}, {"id": "e", "text": "Normal is below 120/80 in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Normal BP is <120/<80 and elevated is 120–129 systolic with diastolic <80.', 'Hypertension Hypotension CO SV - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for HTN stages 1 and 2. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for HTN stages 1 and 2. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Stage 1 starts at SBP 150 in this note."}, {"id": "b", "text": "Stage 2 begins at 140 systolic."}, {"id": "c", "text": "Stage 1 includes 130–139 systolic."}, {"id": "d", "text": "Diastolic thresholds are 80–89 for stage 1 and ≥90 for stage 2."}, {"id": "e", "text": "Stage 2 requires SBP >200 in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Stage 1 HTN is 130–139 or 80–89; stage 2 is ≥140 or ≥90.', 'Hypertension Hypotension CO SV - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and Hypertensive crisis threshold, which statements are correct? (Select all that apply)', 'For blood pressure management and Hypertensive crisis threshold, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Crisis requires low BP in this note."}, {"id": "b", "text": "Crisis threshold includes diastolic above 120."}, {"id": "c", "text": "Crisis is higher risk than stage 2 in this note."}, {"id": "d", "text": "Crisis threshold includes systolic above 180."}, {"id": "e", "text": "Crisis starts at 150/90 in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Hypertensive crisis is listed as BP >180/>120.', 'Hypertension Hypotension CO SV - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around HTN risk factors. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around HTN risk factors. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Age is modifiable in this note."}, {"id": "b", "text": "Smoking and obesity are modifiable risks."}, {"id": "c", "text": "Family history is listed non-modifiable risk."}, {"id": "d", "text": "Stress has no relation to HTN in this note."}, {"id": "e", "text": "High sodium intake is listed modifiable risk."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Non-modifiable risks include age, family history, and race; modifiable include obesity, smoking, high sodium diet, sedentary lifestyle, alcohol, and stress.', 'Hypertension Hypotension CO SV - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support HTN complications? (Select all that apply)', 'During reassessment, which observations support HTN complications? (Select all that apply)', '[{"id": "a", "text": "Retinal damage is listed complication."}, {"id": "b", "text": "CKD is listed complication."}, {"id": "c", "text": "HTN has no end-organ complications in this note."}, {"id": "d", "text": "Only skin complications are listed in this note."}, {"id": "e", "text": "Stroke and MI are listed complications."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Complications listed are stroke, MI, heart failure, CKD, and retinal damage.', 'Hypertension Hypotension CO SV - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Lifestyle HTN management from this note? (Select all that apply)', 'Which clues are consistent with Lifestyle HTN management from this note? (Select all that apply)', '[{"id": "a", "text": "DASH diet is recommended."}, {"id": "b", "text": "Smoking cessation is part of plan."}, {"id": "c", "text": "Exercise and weight loss are recommended."}, {"id": "d", "text": "High-salt diet is recommended for HTN in this note."}, {"id": "e", "text": "Sedentary rest is first-line lifestyle in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Lifestyle management includes DASH (lower sodium/higher potassium), exercise, weight loss, and smoking cessation.', 'Hypertension Hypotension CO SV - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for ACE inhibitor specifics. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for ACE inhibitor specifics. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "ACE inhibitors have no cough risk in this note."}, {"id": "b", "text": "ACE inhibitors are contraindicated in pregnancy."}, {"id": "c", "text": "ACE inhibitors are preferred during pregnancy in this note."}, {"id": "d", "text": "Lisinopril is listed ACE example."}, {"id": "e", "text": "Dry cough is a listed ACE inhibitor side effect."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: ACE inhibitors (e.g., lisinopril) can cause dry cough and are contraindicated in pregnancy.', 'Hypertension Hypotension CO SV - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and ARB specifics, which statements are correct? (Select all that apply)', 'For blood pressure management and ARB specifics, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "ARBs are only emergency IV drugs in this note."}, {"id": "b", "text": "ARBs are used when ACE not tolerated."}, {"id": "c", "text": "ARBs worsen ACE cough in this note."}, {"id": "d", "text": "No-cough advantage is highlighted."}, {"id": "e", "text": "Losartan is listed ARB example."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: ARBs (e.g., losartan) are used if ACE inhibitors are not tolerated and do not cause cough per note.', 'Hypertension Hypotension CO SV - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Thiazide/CCB/beta-blocker roles. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around Thiazide/CCB/beta-blocker roles. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Amlodipine is listed for vasodilation."}, {"id": "b", "text": "Beta-blockers increase contractility in this note."}, {"id": "c", "text": "Metoprolol lowers HR and contractility."}, {"id": "d", "text": "CCBs are listed as preload boosters in this note."}, {"id": "e", "text": "HCTZ is listed first-line for many patients."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Thiazides are first-line for most patients, CCBs cause vasodilation, and beta-blockers reduce HR/contractility.', 'Hypertension Hypotension CO SV - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Hypertensive emergency treatment? (Select all that apply)', 'During reassessment, which observations support Hypertensive emergency treatment? (Select all that apply)', '[{"id": "a", "text": "No organ damage assessment is needed in this note."}, {"id": "b", "text": "Emergency is distinct from asymptomatic severe HTN."}, {"id": "c", "text": "IV nicardipine/labetalol/nitroprusside are listed."}, {"id": "d", "text": "Organ damage presence defines emergency context."}, {"id": "e", "text": "Oral-only delayed treatment is recommended in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Hypertensive emergency with organ damage requires IV antihypertensives such as nicardipine, labetalol, or nitroprusside.', 'Hypertension Hypotension CO SV - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with MAP reduction limit from this note? (Select all that apply)', 'Which clues are consistent with MAP reduction limit from this note? (Select all that apply)', '[{"id": "a", "text": "First-hour MAP reduction cap is 25%."}, {"id": "b", "text": "Reduce MAP by 60% in first hour in this note."}, {"id": "c", "text": "Rapid excessive reduction is unsafe."}, {"id": "d", "text": "MAP-guided titration is emphasized."}, {"id": "e", "text": "MAP has no role in emergency treatment in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: In hypertensive emergency, MAP should not be reduced by more than 25% in the first hour.', 'Hypertension Hypotension CO SV - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Hypotension definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Hypotension definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Hypotension is defined as SBP under 130 in this note."}, {"id": "b", "text": "SBP under 90 is hypotension in this note."}, {"id": "c", "text": "Clinical significance depends on perfusion impact."}, {"id": "d", "text": "DBP under 60 is hypotension in this note."}, {"id": "e", "text": "Any low BP without symptoms is always shock in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Hypotension is systolic <90 or diastolic <60 and is significant when symptoms or hypoperfusion are present.', 'Hypertension Hypotension CO SV - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and Hypotension types and causes, which statements are correct? (Select all that apply)', 'For blood pressure management and Hypotension types and causes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Meds and Addison disease are listed causes."}, {"id": "b", "text": "Sepsis and HF are listed causes."}, {"id": "c", "text": "Orthostatic and hypovolemic are listed types."}, {"id": "d", "text": "Sepsis cannot cause hypotension in this note."}, {"id": "e", "text": "Only neurogenic hypotension exists in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Types listed are orthostatic, hypovolemic, neurogenic, and cardiogenic; causes include bleeding/dehydration, HF, sepsis, medications, and Addison disease.', 'Hypertension Hypotension CO SV - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Orthostatic criteria. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around Orthostatic criteria. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Systolic drop threshold is 20 mmHg."}, {"id": "b", "text": "Diastolic drop threshold is 10 mmHg."}, {"id": "c", "text": "Timing window is within 3 minutes of standing."}, {"id": "d", "text": "Drop must occur after 30 minutes in this note."}, {"id": "e", "text": "Orthostatic criteria require HR rise only in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Orthostatic hypotension is drop ≥20 systolic or ≥10 diastolic within 3 minutes of standing.', 'Hypertension Hypotension CO SV - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Orthostatic management? (Select all that apply)', 'During reassessment, which observations support Orthostatic management? (Select all that apply)', '[{"id": "a", "text": "Hydration should be restricted in orthostasis in this note."}, {"id": "b", "text": "Dangle legs before standing is listed."}, {"id": "c", "text": "Slow position changes are recommended."}, {"id": "d", "text": "Hydration support is recommended."}, {"id": "e", "text": "Rapid standing is preferred in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Nursing actions include dangling legs before standing, slow position changes, and adequate hydration.', 'Hypertension Hypotension CO SV - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Hypotension symptoms from this note? (Select all that apply)', 'Which clues are consistent with Hypotension symptoms from this note? (Select all that apply)', '[{"id": "a", "text": "Low urine output is listed symptom."}, {"id": "b", "text": "Bradycardia is always present in this note."}, {"id": "c", "text": "Warm flushed skin with high urine output is hallmark in this note."}, {"id": "d", "text": "Cool pale skin and tachycardia are listed."}, {"id": "e", "text": "Syncope/dizziness are listed symptoms."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Symptoms include dizziness, syncope, blurred vision, confusion, compensatory tachycardia, cool pale skin, and low urine output.', 'Hypertension Hypotension CO SV - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Hypotension treatment. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Hypotension treatment. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Supine with legs elevated is listed positioning."}, {"id": "b", "text": "Standing position is preferred in severe hypotension in this note."}, {"id": "c", "text": "Norepinephrine/dopamine listed for severe hypotension."}, {"id": "d", "text": "IV fluids/blood products used if hypovolemic."}, {"id": "e", "text": "Diuresis is first-line for hypovolemic hypotension in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Management includes treating cause, IV fluids or blood products for hypovolemia, vasopressors for severe cases, supine position with legs elevated, and slow postural changes.', 'Hypertension Hypotension CO SV - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For blood pressure management and CO factors: heart rate, which statements are correct? (Select all that apply)', 'For blood pressure management and CO factors: heart rate, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Tachycardia and epinephrine can raise CO in table."}, {"id": "b", "text": "Bradycardia can lower CO in table."}, {"id": "c", "text": "HR has no relation to CO in this table."}, {"id": "d", "text": "Bradycardia always raises CO in this note."}, {"id": "e", "text": "Beta-blockers can lower CO via HR effects in table."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: CO can increase with tachycardia/epinephrine and decrease with bradycardia/beta-blockers per table.', 'Hypertension Hypotension CO SV - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around CO factors: preload. Which interventions belong in the plan? (Select all that apply)', 'The nurse plans care around CO factors: preload. Which interventions belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Hemorrhage lowers preload in table."}, {"id": "b", "text": "Preload is unaffected by fluid status in this note."}, {"id": "c", "text": "Hemorrhage raises preload in this note."}, {"id": "d", "text": "Dehydration lowers preload in table."}, {"id": "e", "text": "Higher fluid volume can increase preload/CO."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Preload increase with fluid volume can raise CO; dehydration/hemorrhage lower preload and CO.', 'Hypertension Hypotension CO SV - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support CO factors: afterload/contractility? (Select all that apply)', 'During reassessment, which observations support CO factors: afterload/contractility? (Select all that apply)', '[{"id": "a", "text": "Higher SVR can reduce CO in the table context."}, {"id": "b", "text": "Digoxin/epinephrine increase contractility in table."}, {"id": "c", "text": "HF/MI decrease contractility in table."}, {"id": "d", "text": "HF improves contractility in this note."}, {"id": "e", "text": "Vasoconstriction always increases CO in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Vasodilation (lower SVR) can improve CO while vasoconstriction (higher SVR) can reduce CO; contractility rises with digoxin/epinephrine and falls with HF/MI.', 'Hypertension Hypotension CO SV - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with NCLEX MAP warning from this note? (Select all that apply)', 'Which clues are consistent with NCLEX MAP warning from this note? (Select all that apply)', '[{"id": "a", "text": "MAP 55 is acceptable organ perfusion in this note."}, {"id": "b", "text": "No action needed unless MAP <20 in this note."}, {"id": "c", "text": "Immediate BP support is prioritized."}, {"id": "d", "text": "MAP <60 is ischemia risk in note tip."}, {"id": "e", "text": "Oxygenation support is also prioritized."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: MAP below 60 mmHg means organs are at risk of ischemia and immediate BP/oxygenation support is priority.', 'Hypertension Hypotension CO SV - NCLEX', true, 100, 1, true);
